export interface PgLandmark {
  name: string;
  type: "Station" | "Metro" | "Mall" | "Office" | "College" | "Hospital";
  distanceKm: number;
  minutes: number;
}

export interface PgRoomCard {
  type: string;
  sharing: string;
  priceFrom: number;
  gender: "boys" | "girls" | "any";
  image: string;
  amenities: string[];
  available: number;
  propertySlug?: string;
}

export interface PgFaq {
  q: string;
  a: string;
}

export interface PgServiceArea {
  name: string;
  href: string;
  description: string;
  badge?: string;
}

export interface PgLocationData {
  slug: string;
  area: string;
  city: string;
  headline: string;
  subheadline: string;
  startingRent: number;
  propertyCount: number;
  residentCount: number;
  googleRating: number;
  googleReviews: number;
  station: string;
  pincode: string;
  intro: string;
  whyStay: string[];
  landmarks: PgLandmark[];
  boys: PgRoomCard[];
  girls: PgRoomCard[];
  gallery: { src: string; alt: string }[];
  testimonials: { name: string; role: string; rating: number; text: string }[];
  serviceAreas?: PgServiceArea[];
  seoBlocks: { title: string; body: string }[];
  faqs: PgFaq[];
  mapQuery: string;
}

export type LocationPageType = "main-area" | "sub-area";

export interface LocationPageInheritance {
  parentSlug: string;
  inheritedFields: Array<keyof PgLocationData>;
  overriddenFields: Array<keyof PgLocationData>;
}

export interface LocationPageData extends PgLocationData {
  pageType: LocationPageType;
  mainAreaSlug: string;
  mainArea: string;
  parentSlug?: string;
  parentArea?: string;
  childSlugs: string[];
  inheritance?: LocationPageInheritance;
}

const safeFrontImageNumbers: Record<string, number[]> = {
  "ashok-samrath-building-girls": [2, 3, 5, 6, 9, 10, 11, 13],
  "om-gautam-boys": [1, 2, 5, 6, 8, 10, 11, 12, 14, 15, 16],
  "shivdham-building-1-boys": [2, 3, 7, 9, 10, 11],
  "shivdham-building-1-girls": [1, 2, 3, 5, 6, 10, 11],
  "shivdham-building-boys": [1, 2, 5, 16, 18, 25],
  "vaibhav-kutir-heights": [4, 9, 11, 14, 18, 19, 22],
};

const isSafeFrontImage = (src: string) => {
  const match = src.match(/\/room-images\/([^/]+)\/image-(\d+)\.jpeg$/);
  if (!match) return true;
  const [, folder, imageNumber] = match;
  return safeFrontImageNumbers[folder]?.includes(Number(imageNumber)) ?? false;
};

export const safePreviewGallery = <T extends { src: string; alt?: string }>(gallery: T[]): T[] => gallery.filter((item) => isSafeFrontImage(item.src));

export const safePreviewImageList = (images: string[]): string[] => images.filter((image) => Boolean(image) && isSafeFrontImage(image));

